#include<bits/stdc++.h>
using namespace std;
struct tree {
	int val, left, right, m;
} a[100001];
long long n, x, q;
string c;
void up(int m, int x) {
	if (!x) return;
	a[x].m = a[x].m ^ m;
	a[x].val = a[x].val ^ a[x].m;
	up(a[x].m, a[x].left), up(a[x].m, a[x].right);
}
